Write Go code using context.Context for request cancellation and timeout propagation.

### Solution
```go
package main
import (
    "context"
    "fmt"
    "time"
)

func fetchData(ctx context.Context, id int) (string, error) {
    done := make(chan string, 1)
    go func() {
        time.Sleep(200 * time.Millisecond)  // simulate DB call
        done <- fmt.Sprintf("data for %d", id)
    }()
    select {
    case result := <-done:
        return result, nil
    case <-ctx.Done():
        return "", ctx.Err()
    }
}

func main() {
    // Case 1: enough time
    ctx1, cancel1 := context.WithTimeout(context.Background(), 500*time.Millisecond)
    defer cancel1()
    if r, err := fetchData(ctx1, 1); err == nil { fmt.Println(r) }

