### Task
Implement Go channels for a timeout-aware pipeline with cancellation.

### Solution
```go
package main
import (
    "context"
    "fmt"
    "time"
)

func generate(ctx context.Context, nums ...int) <-chan int {
    out := make(chan int)
    go func() {
        defer close(out)
        for _, n := range nums {
            select {
            case out <- n:
            case <-ctx.Done(): return
            }
        }
    }()
    return out
}

func square(ctx context.Context, in <-chan int) <-chan int {
    out := make(chan int)
    go func() {
        defer close(out)
        for n := range in {
            select {
            case out <- n*n:
            case <-ctx.Done(): return
            }
        }
    }()
    return out
}

func main() {
    ctx, cancel := context.WithTimeout(context.Background(), 50*time.Millisecond)
    defer cancel()
    nums   := generate(ctx, 1,2,3,4,5)
    squares := square(ctx, nums)
    for s := range squares {
        fmt.Println(s)
    }
}
```
Each stage selects between sending output and ctx.Done() — the pipeline drains gracefully when the context is cancelled. Closing channels when goroutines finish prevents goroutine leaks.

