        go func() { defer wg.Done(); c.Inc() }()
    }
    wg.Wait()
    fmt.Println(c.Load())  // always 1000
}
```
atomic operations are CPU-level instructions (LOCK XADD on x86) — no mutex overhead. CompareAndSwap implements optimistic locking patterns. For complex multi-variable updates, a mutex is cleaner; use atomics only for single-variable hot paths.

### Task
Write Go code to stream a large file upload using io.Pipe and multipart.

### Solution
```go
package main
import (
    "fmt"
    "io"
    "mime/multipart"
    "net/http"
    "os"
)

func uploadFile(url, path string) error {
    pr, pw := io.Pipe()
    mw := multipart.NewWriter(pw)

    go func() {
        defer pw.Close()
        part, err := mw.CreateFormFile("file", path)
        if err != nil { pw.CloseWithError(err); return }
        f, err := os.Open(path)
        if err != nil { pw.CloseWithError(err); return }
        defer f.Close()
        io.Copy(part, f)
        mw.Close()
    }()

    req, err := http.NewRequest("POST", url, pr)
    if err != nil { return err }
    req.Header.Set("Content-Type", mw.FormDataContentType())
    resp, err := http.DefaultClient.Do(req)
    if err != nil { return err }
    defer resp.Body.Close()
    fmt.Println(resp.Status)
    return nil
}

func main() {
    uploadFile("https://httpbin.org/post", "data.csv")
}
```
io.Pipe connects the goroutine writing multipart data to the HTTP request body — no intermediate buffer for the whole file. The goroutine writes; the HTTP client reads. pw.CloseWithError propagates errors to the reader side.

