### Task
Write Go code implementing the Observer pattern using channels.

### Solution
```go
package main
import (
    "fmt"
    "sync"
)

type Event struct{ Name, Data string }

type EventBus struct {
    mu   sync.RWMutex
    subs map[string][]chan Event
}

func NewEventBus() *EventBus { return &EventBus{subs: make(map[string][]chan Event)} }

func (b *EventBus) Subscribe(topic string, bufSize int) <-chan Event {
    ch := make(chan Event, bufSize)
    b.mu.Lock()
    b.subs[topic] = append(b.subs[topic], ch)
    b.mu.Unlock()
    return ch
}

func (b *EventBus) Publish(topic string, e Event) {
    b.mu.RLock()
    defer b.mu.RUnlock()
    for _, ch := range b.subs[topic] {
        select {
        case ch <- e:
        default:  // drop if full — non-blocking
        }
    }
}

func main() {
    bus := NewEventBus()
    ch  := bus.Subscribe("order", 10)
    bus.Publish("order", Event{"created", "order-42"})
    e := <-ch
    fmt.Printf("%s: %s\n", e.Name, e.Data)
}
```
Each subscriber gets its own buffered channel — the publisher never blocks. The select-default drop strategy prevents a slow subscriber from stalling publishers. RWMutex allows concurrent reads (Publish) while exclusive writes (Subscribe) are serialised.

