Implement Rust iterators by implementing the Iterator trait on a custom type.

### Solution
```rust
struct Fibonacci { curr: u64, next: u64 }

impl Fibonacci {
    fn new() -> Self { Fibonacci { curr: 0, next: 1 } }
}

impl Iterator for Fibonacci {
    type Item = u64;
    fn next(&mut self) -> Option<u64> {
        let result = self.curr;
        let new_next = self.curr + self.next;
        self.curr = self.next;
        self.next = new_next;
        Some(result)  // infinite iterator — never returns None
    }
