### Task
Write Rust code implementing a simple TCP echo server using std::net.

### Solution
```rust
use std::io::{BufRead, BufReader, Write};
use std::net::{TcpListener, TcpStream};
use std::thread;

fn handle_client(stream: TcpStream) {
    let peer = stream.peer_addr().unwrap();
    println!("Connected: {}", peer);
    let mut writer = stream.try_clone().unwrap();
    let reader = BufReader::new(stream);
    for line in reader.lines() {
        match line {
            Ok(msg) => {
                println!("{}: {}", peer, msg);
                writeln!(writer, "Echo: {}", msg).ok();
            }
            Err(_) => break,
        }
    }
    println!("Disconnected: {}", peer);
}

fn main() -> std::io::Result<()> {
    let listener = TcpListener::bind("127.0.0.1:7878")?;
    println!("Listening on port 7878");
    for stream in listener.incoming() {
        let stream = stream?;
        thread::spawn(|| handle_client(stream));
    }
    Ok(())
}
```
try_clone() creates a second TcpStream wrapping the same socket — one for reading, one for writing, since BufReader consumes the stream. Each connection runs in its own thread. listener.incoming() is an iterator that blocks until a new connection arrives.

