// Simulated clap-derive structure
struct Args {
    input:   PathBuf,
    output:  PathBuf,
    verbose: bool,
    count:   u32,
}

fn parse_args() -> Args {
    // Manual parsing to illustrate the logic clap automates
    let args: Vec<String> = std::env::args().collect();
    let mut input   = PathBuf::from("input.txt");
    let mut output  = PathBuf::from("output.txt");
    let mut verbose = false;
    let mut count   = 1u32;
    let mut i = 1;
    while i < args.len() {
        match args[i].as_str() {
            "--input"   | "-i" => { i+=1; input  = args[i].clone().into(); }
            "--output"  | "-o" => { i+=1; output = args[i].clone().into(); }
            "--verbose" | "-v" => { verbose = true; }
            "--count"   | "-n" => { i+=1; count = args[i].parse().unwrap(); }
            _ => eprintln!("Unknown arg: {}", args[i]),
        }
        i += 1;
    }
    Args { input, output, verbose, count }
}

fn main() {
    let args = parse_args();
    if args.verbose { println!("Verbose mode on"); }
    println!("Input: {:?}, Output: {:?}, Count: {}", args.input, args.output, args.count);
}
