// fn bad() -> &str {
//     let s = String::from("hello");  // s is local
//     &s  // ERROR: s is dropped at end of function, reference dangles
// }

// FIX 1: return owned String
fn good_owned() -> String {
    let s = String::from("hello");
    s  // move the String out
}

// FIX 2: take a reference as input, return it
fn good_ref<'a>(s: &'a str) -> &'a str {
    s  // lifetime of output tied to input
}

// FIX 3: return &'static for literal strings
fn good_static() -> &'static str {
    "hello"  // string literals live for the entire program
}

fn main() {
    let owned  = good_owned();
    let input  = String::from("world");
    let reffed = good_ref(&input);
    let lit    = good_static();
    println!("{} {} {}", owned, reffed, lit);
}
