### Task
Implement Rust channels (mpsc) for a pipeline of data transformations.

### Solution
```rust
use std::sync::mpsc;
use std::thread;

fn main() {
    let (tx1, rx1) = mpsc::channel::<i32>();
    let (tx2, rx2) = mpsc::channel::<i32>();
    let (tx3, rx3) = mpsc::channel::<String>();

    // Stage 1: filter evens
    thread::spawn(move || {
        for n in rx1 { if n % 2 == 0 { tx2.send(n).unwrap(); } }
    });

    // Stage 2: square and format
    thread::spawn(move || {
        for n in rx2 { tx3.send(format!("{}^2={}", n, n*n)).unwrap(); }
    });

    // Producer
    for i in 1..=10 { tx1.send(i).unwrap(); }
    drop(tx1);  // close channel

    // Consumer
    for msg in rx3 { println!("{}", msg); }
}
```
mpsc = multi-producer, single-consumer. Iterating a Receiver blocks until a message arrives or the channel closes. drop(tx1) closes the channel — the stage-1 thread's for loop exits, it drops tx2, and so on down the pipeline.

### Task
Write Rust to implement a simple finite automaton that validates email addresses.

### Solution
```rust
fn is_valid_email(s: &str) -> bool {
    enum State { Start, Local, AtSign, Domain, Dot, TLD }
    let mut state = State::Start;
    for ch in s.chars() {
        state = match state {
            State::Start  if ch.is_alphanumeric() || ch == '_' => State::Local,
            State::Local  if ch.is_alphanumeric() || ch == '_' || ch == '.' || ch == '-' => State::Local,
            State::Local  if ch == '@' => State::AtSign,
            State::AtSign if ch.is_alphanumeric() || ch == '-' => State::Domain,
            State::Domain if ch.is_alphanumeric() || ch == '-' => State::Domain,
            State::Domain if ch == '.' => State::Dot,
            State::Dot    if ch.is_alphabetic() => State::TLD,
            State::TLD    if ch.is_alphabetic() => State::TLD,
            _ => return false,
        };
    }
    matches!(state, State::TLD)
}

fn main() {
    let tests = ["user@example.com", "bad@", "@no.local", "a.b@c.org"];
    for t in &tests { println!("{}: {}", t, is_valid_email(t)); }
}
```
Each match arm transitions to the next state or returns false for invalid input. Final validity is only true in the TLD state. This is more readable than a regex for teaching DFA concepts and has O(n) time with O(1) state storage.

### Task
Implement Rust string parsing with nom-style manual combinators.

### Solution
```rust
type ParseResult<'a, T> = Result<(&'a str, T), &'a str>;

fn tag<'a>(expected: &'static str) -> impl Fn(&'a str) -> ParseResult<'a, &'a str> {
    move |input: &'a str| {
        if input.starts_with(expected) {
            Ok((&input[expected.len()..], &input[..expected.len()]))
        } else {
            Err(input)
        }
    }
}

fn take_while<'a>(pred: impl Fn(char) -> bool) -> impl Fn(&'a str) -> ParseResult<'a, &'a str> {
    move |input: &'a str| {
        let end = input.find(|c| !pred(c)).unwrap_or(input.len());
        Ok((&input[end..], &input[..end]))
    }
}

fn parse_key_value(input: &str) -> ParseResult<(&str, &str)> {
    let key_parser  = take_while(|c| c.is_alphanumeric() || c == '_');
    let (rest, key) = key_parser(input)?;
    let (rest, _)   = tag("=")(rest)?;
    let (rest, val) = take_while(|c| c != ';' && c != '\n')(rest)?;
    Ok((rest, (key, val)))
}

fn main() {
    let (rest, (k,v)) = parse_key_value("host=localhost;port=8080").unwrap();
    println!("key={} val={} rest={}", k, v, rest);
}
```
Parser combinators return (remaining_input, parsed_value). Each parser is a function that fails fast by returning Err. Composing small parsers into larger ones with ? propagation mirrors how nom and winnow work internally.

### Task
Write Rust to use std::process and pipe subcommand stdout into further processing.

### Solution
```rust
use std::process::{Command, Stdio};
use std::io::{BufRead, BufReader};

fn count_lines(path: &str) -> usize {
    // Spawn `wc -l filename` (Unix) or manual line-count (cross-platform)
    let output = Command::new("python")
        .args(["-c", &format!("print(sum(1 for _ in open(r'{}')))", path)])
        .output()
        .expect("failed to run python");
    String::from_utf8_lossy(&output.stdout).trim().parse().unwrap_or(0)
}

fn stream_output(cmd: &str, args: &[&str]) {
    let mut child = Command::new(cmd)
        .args(args)
        .stdout(Stdio::piped())
        .spawn()
        .expect("spawn failed");
    let stdout = child.stdout.take().unwrap();
    for line in BufReader::new(stdout).lines() {
        println!(">> {}", line.unwrap());
    }
    child.wait().unwrap();
}

fn main() {
    stream_output("python", &["-c", "for i in range(5): print(i)"]);
}
```
Stdio::piped() redirects the child's stdout to a pipe we can read. stdout.take() pulls ownership of the pipe. BufReader::new streams lines lazily — the parent processes each line as the child produces it, with no full-output buffering.
